slides.css:
.slide-container {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  height: 100%;
  padding: 120px 80px;
  background-color: #000000;
  color: #ffffff;
  font-family: 'Pretendard', sans-serif;
  word-break: keep-all;
  box-sizing: border-box;
}
.top-tier {
  font-size: 32px;
  font-weight: 700;
  color: #888888;
  text-transform: uppercase;
  letter-spacing: 2px;
  border-bottom: 1px solid #333333;
  padding-bottom: 24px;
}
.mid-tier {
  flex-grow: 1;
  display: flex;
  align-items: center;
}
.mid-tier h1 {
  font-size: 72px;
  font-weight: 800;
  line-height: 1.4;
  margin: 0;
  letter-spacing: -2px;
}
.bot-tier {
  font-size: 44px;
  font-weight: 500;
  color: #aaaaaa;
  line-height: 1.5;
  border-left: 4px solid #ffffff;
  padding-left: 28px;
  margin-bottom: 40px;
}
.bot-tier p {
  margin: 0;
}

